// Cluster articles by topic into groups of 3+ for story synthesis
const allItems = $('Fetch Recent Articles').all();
const articles = allItems.map(item => item.json).filter(a => a.topic_tags && a.topic_tags.length > 0);

if (articles.length < 3) {
  return [{ json: { _skip: true, reason: 'Not enough articles for clustering' } }];
}

// Group by primary topic tag
const topicGroups = {};
for (const art of articles) {
  const tags = art.topic_tags || ['General'];
  const primary = tags[0];
  if (!topicGroups[primary]) topicGroups[primary] = [];
  topicGroups[primary].push(art);
}

// Build clusters: minimum 3 articles per cluster
const clusters = [];
const smallGroups = [];

for (const [topic, arts] of Object.entries(topicGroups)) {
  if (arts.length >= 3) {
    // If large group, sub-cluster by region
    if (arts.length > 12) {
      const byRegion = {};
      for (const a of arts) {
        const r = a.region || 'Global';
        if (!byRegion[r]) byRegion[r] = [];
        byRegion[r].push(a);
      }
      for (const [region, regionArts] of Object.entries(byRegion)) {
        if (regionArts.length >= 3) {
          clusters.push({ topic, region, articles: regionArts.slice(0, 10) });
        } else {
          smallGroups.push(...regionArts);
        }
      }
    } else {
      // Determine dominant region
      const regionCounts = {};
      for (const a of arts) {
        const r = a.region || 'Global';
        regionCounts[r] = (regionCounts[r] || 0) + 1;
      }
      const topRegion = Object.entries(regionCounts).sort((a,b) => b[1]-a[1])[0][0];
      clusters.push({ topic, region: topRegion, articles: arts.slice(0, 10) });
    }
  } else {
    smallGroups.push(...arts);
  }
}

// Merge small groups into a 'Mixed' cluster if enough
if (smallGroups.length >= 3) {
  clusters.push({ topic: 'Mixed', region: 'Global', articles: smallGroups.slice(0, 10) });
}

// Sort by article count (most coverage = most newsworthy)
clusters.sort((a, b) => b.articles.length - a.articles.length);

// Take top 8 clusters to manage API costs
const topClusters = clusters.slice(0, 8);

if (topClusters.length === 0) {
  return [{ json: { _skip: true, reason: 'No viable clusters found' } }];
}

// Output one item per cluster
return topClusters.map((cluster, idx) => ({
  json: {
    cluster_index: idx,
    cluster_topic: cluster.topic,
    cluster_region: cluster.region,
    article_count: cluster.articles.length,
    article_ids: cluster.articles.map(a => a.id),
    is_top_cluster: idx === 0,
    // Build the prompt context: titles + excerpts
    image_url: (cluster.articles.find(a => a.image_url) || {}).image_url || null,
    articles_context: cluster.articles.map(a =>
      `[${a.source_name || 'Unknown'}] ${a.title}\n${(a.excerpt || a.content || '').substring(0, 400)}`
    ).join('\n\n---\n\n')
  }
}));

// Parse Claude response and build story records for Supabase
const items = $input.all();
const clusterItems = $('Filter Skip').all();
const stories = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const cluster = clusterItems[i]?.json || {};

  try {
    // Extract Claude's response text
    let responseText = '';
    if (item.json.content && Array.isArray(item.json.content)) {
      responseText = item.json.content.map(c => c.text || '').join('');
    } else if (typeof item.json === 'string') {
      responseText = item.json;
    } else if (item.json.error) {
      continue; // Skip failed API calls
    }

    // Clean up response: remove markdown fences if present
    responseText = responseText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

    // Find the JSON object in the response (Claude sometimes adds text before/after)
    const jsonStart = responseText.indexOf('{');
    const jsonEnd = responseText.lastIndexOf('}');
    if (jsonStart === -1 || jsonEnd === -1) continue;
    responseText = responseText.substring(jsonStart, jsonEnd + 1);

    const story = JSON.parse(responseText);
    if (!story.title) continue;

    // Generate content hash for caching
    let hash = 0;
    const hashStr = story.title + story.synthetic_content;
    for (let j = 0; j < hashStr.length; j++) {
      hash = ((hash << 5) - hash + hashStr.charCodeAt(j)) | 0;
    }
    const contentHash = Math.abs(hash).toString(16);

    stories.push({
      json: {
        title: story.title || 'Untitled Story',
        synopsis: story.synopsis || '',
        synthetic_content: story.synthetic_content || '',
        source_count: cluster.article_count || 0,
        source_article_ids: cluster.article_ids || [],
        labels: story.labels || [],
        cluster_topic: cluster.cluster_topic || 'General',
        region: cluster.cluster_region || 'Global',
        is_featured: cluster.is_top_cluster && (story.significance_rating || 0) >= 7,
        content_hash: contentHash,
        timeline_entries: story.timeline_entries || [],
        confidence_score: Math.min(1, Math.max(0, story.confidence_score || 0.5)),
        image_url: cluster.image_url || null
      }
    });
  } catch(e) {
    // Skip malformed responses
  }
}

if (stories.length === 0) {
  return [{ json: { _skip: true, reason: 'No stories could be parsed' } }];
}

return stories;
